mapper.sql:
SELECT ID, SHIPVOYAGE_ID, SHIP_ID, SHIP_NAME, SHIP_DYNAMIC_ID, TUG_ID, TUG_NAME, TUG_SERVICE_TYPE, TUG_SERVICE_TYPE_NAME, START_TIME, END_TIME, TIME_LENGTH, REMARK, IS_STANDARD_USE, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM T_DIS_TUG_SERVICE_RECORD
and SHIPVOYAGE_ID = #{shipvoyageId}
and TUG_ID = #{tugId}
and TO_CHAR(START_TIME, 'YYYY-MM-DD') >= #{startTime}
and TO_CHAR(END_TIME, 'YYYY-MM-DD') <= #{endTime}

mapper.select:
SELECT A.TUG_NAME, CASE WHEN C.VOYAGE IS NOT NULL THEN A.SHIP_NAME || '_' || C.VOYAGE WHEN D.VOYAGE IS NOT NULL THEN A.SHIP_NAME || '_' || D.VOYAGE WHEN (C.VOYAGE IS NOT NULL AND D.VOYAGE IS NOT NULL) THEN A.SHIP_NAME || '_' || C.VOYAGE || '/' || D.VOYAGE END AS SHIP_VOYAGE, B.SCN, A.TUG_SERVICE_TYPE_NAME, A.START_TIME, A.END_TIME, A.TIME_LENGTH, A.REMARK, A.IS_STANDARD_USE, A.CREATE_BY, A.CREATE_BY_NAME, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_BY_NAME, A.UPDATE_TIME FROM T_DIS_TUG_SERVICE_RECORD A LEFT JOIN T_DIS_SHIPVOYAGE B ON A.SHIPVOYAGE_ID = B.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM C ON B.ID = C.SHIPVOYAGE_ID AND C.IMP_EXP = 'IN' LEFT JOIN T_DIS_SHIPVOYAGE_ITEM D ON B.ID = D.SHIPVOYAGE_ID AND D.IMP_EXP = 'OUT'
and (C.ID = #{shipvoyageId} OR D.ID = #{shipvoyageId})
and B.SCN = #{scn}
and A.TUG_ID = #{tugId}
and TO_CHAR(A.START_TIME, 'YYYY-MM-DD') >= #{startTime}
and TO_CHAR(A.END_TIME, 'YYYY-MM-DD') <= #{endTime}

SELECT A.ID, A.SHIPVOYAGE_ID, NVL(A.SHIPVOYAGE_ITEM_ID,(NVL(C.ID,D.ID))) SHIPVOYAGE_ITEM_ID, A.SHIP_ID, A.SHIP_NAME || '_' || C.VOYAGE || '/' ||D.VOYAGE AS SHIP_VOYAGE, B.SCN, A.SHIP_DYNAMIC_ID, A.TUG_ID, A.TUG_NAME, A.TUG_SERVICE_TYPE, A.TUG_SERVICE_TYPE_NAME, A.START_TIME, A.END_TIME, A.TIME_LENGTH, A.REMARK, A.IS_STANDARD_USE, A.CREATE_BY, A.CREATE_BY_NAME, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_BY_NAME, A.UPDATE_TIME FROM T_DIS_TUG_SERVICE_RECORD A LEFT JOIN T_DIS_SHIPVOYAGE B ON A.SHIPVOYAGE_ID = B.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM C ON B.ID = C.SHIPVOYAGE_ID AND C.IMP_EXP = 'IN' LEFT JOIN T_DIS_SHIPVOYAGE_ITEM D ON B.ID = D.SHIPVOYAGE_ID AND D.IMP_EXP = 'OUT'
and (C.ID = #{shipvoyageId} OR D.ID = #{shipvoyageId})
and B.SCN = #{scn}
and A.TUG_ID = #{tugId}
and TO_CHAR(A.START_TIME, 'YYYY-MM-DD') >= #{startTime}
and TO_CHAR(A.END_TIME, 'YYYY-MM-DD') <= #{endTime}
ORDER BY A.START_TIME DESC nulls last
